;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading) events.push2(3);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7, 8, 9]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@roadguide w="Northrop Village"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("vitality", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Vitality permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

@callbattle normal=true

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@se f=period
@eval exp='o.フーラ雪原・南の森.setWarp(4, 26, "D", "warp")'
@eval exp='o.ヤネクの森・西.setWarp(10, 6, "D", "warp")'
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] true

@addevent name=アウラ教会 num=0
@shop name=アウラ教会
@walk turn=n move=n
[texton]
[シスター]「Please come again.」[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger || inSearching

@grave

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] onObjectTrigger || inSearching

@grave monster=ガスト

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] onObjectTrigger || inSearching

[if exp='game.inSearching && game.findItem(o.ペリドットの魔石) === void']
	@se f=period
	@eval exp='game.storeItemSomewhere(%[itemData: o.ペリドットの魔石])'
	@notice text="Surprisingly, found the <p>Peridot Magic Stone<w>!"
	[eventoff]
[endif]
@grave name=Ferrucci

[eventoff]
;-------------------------------------------------------------------------------
*event_9
;[exp] onObjectTrigger

@notice text="Northrop Village"

[eventoff]
;-------------------------------------------------------------------------------
*event_10
;[exp] true

@notice text="You can't go any further in the trial version."
@walk move=s

[eventoff]
;-------------------------------------------------------------------------------
